export default function delegate(root, eventType, selector, handler) {
  if (!root || typeof root.addEventListener !== 'function') {
    throw new TypeError('delegate: root must be an Element');
  }
  if (typeof eventType !== 'string') {
    throw new TypeError('delegate: eventType must be a string');
  }
  if (typeof selector !== 'string') {
    throw new TypeError('delegate: selector must be a string');
  }
  if (typeof handler !== 'function') {
    throw new TypeError('delegate: handler must be a function');
  }

  const listener = (event) => {
    const target = event && event.target;
    if (!target || target.nodeType !== 1) return;

    const el = target;
    const matched = el.closest(selector);
    if (!matched) return;

    if (matched === root || root.contains(matched)) {
      handler(event, matched);
    }
  };

  root.addEventListener(eventType, listener);

  return function cleanup() {
    root.removeEventListener(eventType, listener);
  };
}
